form:Form.form:Scripts:
		function ClearEmpresa()
{
	Ctrl("oi_empresa").SetCValue("");                     
	ClearPuesto();
}

function ClearPuesto()
{                     
	Ctrl("oi_puesto").SetCValue("");
	ClearPosicion();
}

function ClearPosicion()
{                     
	Ctrl("oi_posicion").SetCValue("");
}




function EJECUTAR_CLICK()
{                             
	if (Ctrl("oi_empresa").GetXValue()=="") { alert("La Empresa es Requerida."); return false; }      
	if (Ctrl("oi_aniomes").GetXValue()=="") { alert("Mes/Año es Requerido."); return false; }

	if (!Ctrl("main").Validate()) return false;



    /*



var mdx ="with set [Mayores_60] as '{([Edades].[Todos las Edades].[60] : [Edades].[Todos las Edades].[69])}' " ;
    mdx +="   set [Mayores_55] as '{([Edades].[Todos las Edades].[55] : [Edades].[Todos las Edades].[69])}'  " ;
    mdx +="   member [Measures].[Mayores_60] as 'Sum([Mayores_60], [Measures].[Cantidad])' " ;
    mdx +="   member [Measures].[Mayores_55] as 'Sum([Mayores_55], [Measures].[Cantidad])' " ;
    mdx +="   member [Measures].[Mayores a 55] as '([Measures].[Mayores_55] / [Measures].[Cantidad])', FORMAT_STRING = '#%' " ;
    mdx +="   member [Measures].[Mayores a 60] as '([Measures].[Mayores_60] / [Measures].[Cantidad])', FORMAT_STRING = '#%' " ;
    mdx +=" select NON EMPTY {[Measures].[Cantidad], [Measures].[Mayores a 55] , [Measures].[Mayores a 60]} ON COLUMNS, " ;
    mdx +="   NON EMPTY Order({[Sexos].[Ambos Sexos].[FEMENINO], [Sexos].[Ambos Sexos].[MASCULINO]}, [Measures].[Mayores a 55], DESC) ON ROWS  " ;
    mdx +=" from [PERSONAL] " ;
      */
 var mdx ="with   set [Cantidad Mayor 60] as '{([Edades].[Todos las Edades].[61] : [Edades].[Todos las Edades].[69])}' " ;
    mdx +="     set [Cantidad Mayor 55] as '{([Edades].[Todos las Edades].[56] : [Edades].[Todos las Edades].[69])}' " ;
      mdx +="   member [Measures].[Cantidad Mayor 60] as 'Sum([Cantidad Mayor 60], [Measures].[Cantidad])' " ;
      mdx +="   member [Measures].[Cantidad Mayor 55] as 'Sum([Cantidad Mayor 55], [Measures].[Cantidad])' " ;
      mdx +="   member [Measures].[Porcentaje55] as '([Measures].[Cantidad Mayor 55] / [Measures].[Cantidad])', FORMAT_STRING = '#%' " ;
      mdx +="   member [Measures].[Porcentaje60] as '([Measures].[Cantidad Mayor 60] / [Measures].[Cantidad])', FORMAT_STRING = '#%' " ;
      mdx +="   member [Measures].[Total] as '([Measures].[Cantidad])' " ;
    mdx +="   select NON EMPTY {[Measures].[Total], [Measures].[Cantidad Mayor 55],[Measures].[Porcentaje55],  [Measures].[Cantidad Mayor 60],[Measures].[Porcentaje60]} ON COLUMNS, " ;
      mdx +="    ({[Sexos].[Ambos Sexos].[FEMENINO], [Sexos].[Ambos Sexos].[MASCULINO]}) ON ROWS " ;
    mdx +="   from [PERSONAL] " ;




	var where = "";
	if(Ctrl("oi_aniomes").GetCValue()!="")
		where += "[Tiempo].[" + Ctrl("oi_aniomes").GetCValue().split("/")[1] + "].[" + Ctrl("oi_aniomes").GetCValue() + "],";

	if(Ctrl("oi_empresa").GetText(1)!="")
		where += "[Empresas].[" + Ctrl("oi_empresa").GetText(1) + "],";

	if(where!="")
	{                   
		mdx += "where {(" + where.substr(0, where.length-1) + ")}";
	}

//alert(mdx);

	Ctrl("mdx").SetXValue(mdx);

	Ctrl("main").DoEvent("EJECUTAR_CLICK");
	return true;
}           

function OnLoad()
{                              
	if  (Ctrl("Estado").GetXValue()=="Sin Errores") 
	{ 	CtrlEnabled("btn_logTCO",false	);          }
	else
	{ 	CtrlEnabled("btn_logTCO",true);              }
}
function showLogTCO()
{
	openNewFlowWait("NucleusRH.Base.Indicadores.logTCO.flow","initialize","<param modulo=\"personal\" />",new ObjtectResult(),"L");
}

function ObjtectResult()
{        
	this.processResult= function(xmlin){}
}
